#!/usr/bin/env node
/**
 * Adds CITY_ROOF_EXTRA, CITY_ROOF_EXTRA2, and CITY_ROOF_MAINT entries
 * for 10 new metros to build-flagship-roofing.js.
 */
const fs = require("fs");
const path = require("path");
const ROOT = path.resolve(__dirname, "..");
const FILE = path.join(ROOT, "scripts/build-flagship-roofing.js");

const EXTRAS = {
  "st-louis-mo": {
    dominantMaterialPara: `St. Louis residential roofing splits along the city-county divide: City of St. Louis homes in the Central West End, Lafayette Square, and Soulard carry architectural composition on 1880s-1920s brick Second Empire, Italianate, and Victorian four-square construction, while newer St. Louis County construction in Chesterfield, Wildwood, and Ballwin runs dimensional composition on 1970s-2000s ranch and contemporary. Slate appears on Lafayette Square and Compton Heights landmarked mansions. The Hill neighborhood's dense 1920s brick construction features flat-roof modified bitumen and EPDM systems similar to Chicago three-flats.`,
    windHailRiskPara: `St. Louis sits at the convergence of Great Plains supercell corridors and Gulf moisture: the metro averages 2-4 damaging hail events annually with spring supercells tracking northeast across St. Charles County into Metro East. The April 2011 Good Friday tornado (EF4) devastated Lambert Airport and north St. Louis County, and the August 2020 derecho produced 80-100 mph straight-line winds across the entire metro. ASCE 7-22 rates St. Louis at 105 mph design wind speed. Class 4 impact-rated assemblies deliver 10-20% insurance premium reductions on most Missouri and Illinois homeowners policies.`,
    permitSpecificityPara: `City of St. Louis Building Division permits residential reroofs within 5-10 business days at $150 minimum. St. Louis County processes separately with 3-5 day turnaround. Missouri has no statewide contractor licensing for roofers; both jurisdictions require local contractor registration and insurance verification. Historic districts under the City of St. Louis Cultural Resources Office include Lafayette Square, Benton Park, Fox Park, Soulard, Tower Grove East, Compton Heights, and Shaw. Landmark review adds 4-8 weeks and typically requires matching original slate, composition profiles, or specific clay tile on contributing structures.`,
    warrantyCulturePara: `St. Louis composition contractors offer GAF Golden Pledge (50-year material, 25-year workmanship), Owens Corning Platinum Preferred, and CertainTeed SureStart PLUS. Class 4 impact-rated products (Malarkey Legacy with SBS-modified asphalt, GAF Timberline AS, IKO Dynasty) carry additional 50-year impact-resistance warranty. Missouri's spring hail frequency makes Class 4 warranties functionally important, not just marketing. Slate contractors on Lafayette Square and Compton Heights landmarked homes offer 75-100 year material warranty on Pennsylvania or Vermont slate.`,
    insuranceClaimCulturePara: `Missouri carriers handle hail and wind damage under standard homeowners policies, and the metro's spring hail frequency means roof-condition underwriting is a major factor. Most carriers require roof inspection on homes with 15+ year roofs, and several apply ACV settlement on roofs over 20 years. Class 4 impact-rated assemblies yield 10-20% premium reductions on most Missouri policies. Missouri Revised Statutes Section 375.1007 prohibits unfair claim settlement practices. Document hail damage within 30 days of any spring supercell event with dated exterior and interior photos.`,
    localManufacturerPara: `GAF ships to St. Louis through the Kansas City and Indianapolis distribution hubs with 1-3 day lead times. Owens Corning manufactures at the Irving TX and Kansas City plants. CertainTeed ships from Shakopee MN and Corsicana TX. Atlas Roofing operates the Daingerfield TX plant. Malarkey ships from Portland OR. IKO ships from Canadian plants via Great Lakes rail. St. Louis distributors include ABC Supply (multiple metro locations), Beacon Roofing Supply, SRS Distribution, and Allied Building Products. Penn Big Bed Slate from Slatington PA supplies landmarked restoration projects with 4-8 week lead times.`,
    gutterIntegrationPara: `St. Louis gutter integration must handle both ice-dam risk from freeze-thaw cycling and high-volume summer thunderstorm runoff. K-style aluminum 6-inch gutters with 3x4 downspouts are the metro spec. Ice-and-water-shield at eaves extending 3 feet minimum from exterior wall is the Missouri-standard spec. Heated cable systems at eaves run $8-$15 per linear foot for persistent ice-dam homes on north-facing slopes in University City and Maplewood. Copper gutters appear on Lafayette Square landmarked mansions. The Hill neighborhood's flat-roof homes require specific scupper and internal-drain sizing.`,
    solarIntegrationPara: `St. Louis solar adoption is growing under the 30% federal ITC plus Ameren Missouri net-metering under Missouri's net-metering statute (RSMo 386.890). A 7-10 kW south-facing St. Louis composition roof installation returns 9-13 year payback. Missouri Renewable Energy Standard requires Ameren to procure 15% renewable by 2021 with carve-outs for solar; SREC market has historically been modest. Illinois side of the metro (Metro East) operates under Illinois Shines program with stronger incentives. Critical coordination: schedule reroof BEFORE solar when panels are within 3-5 years.`,
    historicDistrictPara: `St. Louis has 30+ locally designated historic districts and 200+ National Register-listed properties under the City of St. Louis Cultural Resources Office. Districts include Lafayette Square, Benton Park, Compton Heights, Fox Park, Soulard, Tower Grove East, Tower Grove South, Shaw, Forest Park Southeast, Central West End, Skinker-DeBaliviere, West End, North Central, Hyde Park, Old North St. Louis, and the Gaslight Square area. Landmark review requires matching original material profiles: slate on Second Empire and Italianate, specific composition on vernacular brick four-squares, and clay tile on Tudor Revival.`,
    commonUpsellPara: `St. Louis reroof upsells worth accepting: upgrade to Class 4 impact-rated composition (10-20% Missouri insurance premium reduction), upgrade to ice-and-water-shield extending 6 feet from eaves on low-slope sections (cheap insurance against freeze-thaw ice dams), upgrade to synthetic underlayment from organic felt (survives Missouri seasonal cycling 25+ years vs 15-20 on felt), and upgrade to reinforced starter course. Upsells to decline: excessive ridge ventilation beyond balanced intake-exhaust, unnecessary skylight additions, and proprietary "Gateway-rated" products without independent UL 2218 or FM 4473 certification.`,
    seasonalPricingDeepPara: `St. Louis reroof pricing peaks April through June during spring-hail-claim surge and optimal install conditions. Post-derecho and post-tornado claim surges can double normal scheduling delays for 6-12 months. October through December sees softer pricing (10-20% below peak) and faster scheduling (3-5 week availability vs 8-14 weeks during spring surge). Sub-freezing ambient from December through February compromises sealant activation on most composition products. Best scheduling window runs September through November before deep freeze but after summer heat-dome conditions.`,
    localRoofCountPara: `St. Louis metro (City of St. Louis, St. Louis County, St. Charles, Jefferson, Franklin, Lincoln counties plus Metro East) has approximately 1.1 million single-family homes. Composition dominates at roughly 82%, with modified bitumen and EPDM flat-roof at 9%, slate on landmarked homes at 3%, metal at 4%, and other at 2%. Average reroof cycle is 18-24 years on composition (hail-driven rather than UV). City of St. Louis Building Division pulls approximately 8,000-15,000 roof permits annually; metro-wide runs 40,000-65,000 in typical years, with significant spikes in post-storm years.`,
  },
  "orlando-fl": {
    dominantMaterialPara: `Orlando's roofing stock centers on flat-profile and S-tile concrete (Eagle, Boral, Hanson) on 1990s-2020s CBS construction across Dr. Phillips, Lake Nona, Windermere, and Celebration, architectural composition on 1960s-1980s ranch and split-level homes in College Park, Colonialtown, and Winter Park, and increasingly standing-seam metal on higher-end lakefront builds. Tile dominance in newer Orlando subdivisions reflects the Florida Building Code's wind-uplift emphasis and the insurance-credit advantages of concrete-tile weight and fire resistance.`,
    windHailRiskPara: `Orlando hail is rare (annual expectation 0-1 damaging events) but hurricane exposure is direct: Charley 2004, Irma 2017, and Ian 2022 all affected the Orlando metro with significant roof damage. ASCE 7-22 rates Orange County at 130-140 mph design wind speed. Florida Building Code HVHZ provisions apply in coastal counties, but Orange County's interior position still requires high-wind-rated products. Afternoon summer thunderstorms with 60+ mph microbursts produce localized damage annually, particularly in the exposed I-4 corridor communities of Kissimmee and Sanford.`,
    permitSpecificityPara: `City of Orlando Permitting Services Division and Orange County Building Department both accept residential reroof applications online at $150-$200 minimum. FPA (Florida Product Approval) documentation is required on every product. Winter Park, Maitland, and Windermere each have separate permitting processes. Orlando Historic Preservation Board oversees the Lake Eola Heights, Colonialtown, Lake Lawsona, Delaney Park, and Thornton Park districts. Landmark review adds 4-8 weeks. Seminole County (Altamonte Springs, Casselberry, Oviedo) requires separate county permits with 5-10 day turnaround.`,
    warrantyCulturePara: `Orlando composition contractors anchor on GAF Golden Pledge, OC Platinum Preferred, and CertainTeed SureStart PLUS, all requiring certified-installer status. Atlas Signature Select is common in the Central Florida market. Concrete tile warranties run 50-75 years on tile material with 20-25 year underlayment warranties on synthetic systems. Standing-seam metal on lakefront custom builds carries 40-50 year Kynar 500 paint warranty. Every product installed in Orange County must carry current FPA approval; non-FPA installation fails final inspection regardless of manufacturer warranty terms.`,
    insuranceClaimCulturePara: `Orlando insurance carriers handle hurricane and wind damage but have tightened roof-age underwriting post-Ian. Most carriers require roof inspection on 15+ year roofs. Citizens Property Insurance backs a growing share of Central Florida policies. The OIR-B1-1802 wind-mitigation inspection yields 15-30% premium reductions for SWRB at the roof deck plus FPA-rated product installation. Florida Statute Section 627.70152 governs hurricane deductible caps. Document storm damage within 72 hours. Orlando's inland position means lower premiums than coastal metros, but post-Ian pricing still increased 15-25% metro-wide.`,
    localManufacturerPara: `Eagle Roofing Products ships concrete tile from the Sulphur Springs FL plant with 1-2 day Orlando delivery. Boral tiles come from the Palatka FL plant. GAF composition routes through the Jacksonville and Tampa distribution hubs to ABC Supply Orlando, Beacon Roofing Supply (multiple Orange and Seminole County locations), and SRS Distribution. Atlas Roofing ships from the Cordele GA plant with 2-3 day lead times. CertainTeed ships from Shreveport LA. McElroy Metal operates Florida distribution for standing-seam panels with 5-7 day turnaround on custom profiles.`,
    gutterIntegrationPara: `Orlando gutter specs must handle intense afternoon thunderstorm downpours that can deliver 2-4 inches per hour. K-style aluminum 6-inch gutters with 3x4 downspouts are the Central Florida standard. Many 1990s-2000s subdivisions in Dr. Phillips, Lake Nona, and Windermere were delivered without gutters, relying on wide eave overhang and Florida's sandy soil for drainage; this works on sandy lots but fails near clay-pocket neighborhoods. Gutter guards at $5-$9 per linear foot manage live oak and cabbage palm debris in tree-dense Winter Park and College Park properties.`,
    solarIntegrationPara: `Orlando solar adoption is growing under the 30% federal ITC plus Duke Energy Florida and OUC net-metering. Florida's net-metering framework provides 1-for-1 retail-rate credits for exported energy. A 7-12 kW south-facing Orlando composition or tile roof system returns 8-11 year payback. Florida statute 163.04 prevents HOAs from prohibiting solar installations. Afternoon thunderstorm cloud cover from June through September clips 10-15% off theoretical summer production. Tile-roof solar requires QuickMount PV or IronRidge TileMount flashing sets and licensed tile sub-coordination.`,
    historicDistrictPara: `Orlando has locally designated historic districts under the Orlando Historic Preservation Board including Lake Eola Heights (1910s-1940s bungalows and Mediterranean Revival), Colonialtown North and South, Lake Lawsona/Lake Lucerne, Thornton Park, Delaney Park, and segments of the Orwin Manor and Park Lake Highlands neighborhoods. Winter Park has its own historic preservation program covering portions of the downtown and Park Avenue corridor. National Register-listed properties include the Greeneda Court, Rose Garden Inn, and scattered Craftsman bungalows. Approved materials on contributing structures typically match original composition or tile profiles from 1910s-1940s construction.`,
    commonUpsellPara: `Orlando reroof upsells worth accepting: SWRB peel-and-stick at roof deck (the single largest insurance-credit return in Central Florida), upgrade to synthetic underlayment from organic felt (Florida humidity degrades felt in 12-15 years), FPA-rated hip-to-gable conversion when structurally feasible (8-15% premium reduction). Upsells to decline: unnecessary powered ridge vents (Orlando's low-differential attic minimizes stack effect), proprietary products without verifiable FPA numbers at floridabuilding.org, and "hurricane-proof" branding without independent ASTM testing documentation.`,
    seasonalPricingDeepPara: `Orlando reroof pricing peaks October through March during non-hurricane-season install and snowbird-season demand. June through September hurricane season sees scheduling disrupted by tropical system watches and afternoon thunderstorm windows. Post-Ian 2022 supply chain disruption pushed Central Florida reroof timelines to 10-16 weeks through mid-2023. Best pricing typically runs May and late November (10-15% below peak). The ideal Central Florida install window balances dry weather, reasonable heat, and off-peak demand: late October through early December and March through early May.`,
    localRoofCountPara: `Orlando metro (Orange, Seminole, Osceola, Lake counties) has approximately 850,000 single-family homes with 3-4% annual growth driven by continued population influx. Concrete tile covers roughly 55% of the metro's housing stock, composition 38%, metal 5%, and other 2%. Average reroof cycle is 25-35 years on tile (underlayment-driven) and 15-20 years on composition (UV and storm exposure). Orange County Building Department pulls approximately 22,000-35,000 roof permits annually; metro-wide runs 55,000-90,000 in typical years.`,
  },
  "san-antonio-tx": {
    dominantMaterialPara: `San Antonio's roofing market centers on architectural composition (GAF Timberline HDZ, OC Duration, CertainTeed Landmark) across the majority of Bexar County's single-family housing, with Class 4 impact-rated composition (Malarkey Legacy, GAF Timberline AS) gaining rapid adoption after the April 2016 and March 2024 hail events. Stone Oak, The Dominion, and Alamo Heights see higher-end standing-seam metal and clay tile on Spanish Colonial Revival homes. The King William Historic District features slate and standing-seam metal on 1870s-1920s Victorian and Italianate mansions along the San Antonio River.`,
    windHailRiskPara: `San Antonio sits at the southern edge of the Texas hail corridor: the metro averages 2-3 damaging hail events annually, concentrated in March through June supercell season. The April 2016 hail event produced $1.4 billion in insured losses across Bexar County. ASCE 7-22 rates San Antonio at 100 mph design wind speed. Gulf moisture-driven severe weather crosses the Hill Country and descends into the San Antonio basin during spring, and rare tornado events (2017 northeast Bexar County) add wind-uplift risk. Class 4 impact-rated assemblies deliver 15-25% insurance premium reductions on most Texas carriers.`,
    permitSpecificityPara: `City of San Antonio Development Services Department permits residential reroofs through the online portal within 3-7 business days at $175 minimum. Texas has no statewide roofing contractor license; TDLR registers only mechanical and electrical trades. San Antonio Historic and Design Review Commission (HDRC) oversees the King William, Lavaca, Government Hill, Monte Vista, Dignowity Hill, Tobin Hill, and Mahncke Park historic districts. Landmark review on contributing structures adds 4-8 weeks and requires materials matching original slate, composition, or clay tile profiles from 1870s-1940s construction.`,
    warrantyCulturePara: `San Antonio Class 4 contractor installations anchor on Malarkey Legacy (50-year SBS-modified asphalt with impact-resistance warranty), GAF Timberline AS (polymer-modified for impact), and IKO Dynasty. Standard composition uses GAF Golden Pledge, OC Platinum Preferred, or CertainTeed SureStart PLUS. Texas hail frequency makes the impact-resistance warranty functionally valuable: hail damage replacement frequency drops from every 8-12 years on standard composition to every 15-20+ years on Class 4. Slate warranties on King William landmarked homes run 75-100 year material with 25-year flashing.`,
    insuranceClaimCulturePara: `Texas carriers aggressively incentivize Class 4 impact-rated assemblies: most San Antonio policies yield 15-25% premium reductions with verified Class 4 installation. Post-hail storm-chase crews from Oklahoma, Alabama, and Arkansas are the highest-risk contractor category in the San Antonio market. Texas Insurance Code Section 4102.207 prohibits contractors from absorbing or "eating" deductibles on insurance claims; any contractor offering that arrangement is committing insurance fraud. Document hail damage within 30 days of any spring event with dated exterior photos.`,
    localManufacturerPara: `GAF ships to San Antonio through the Dallas and Houston distribution hubs with 1-2 day lead times. Owens Corning manufactures at the Irving TX plant with same-day or next-day delivery. CertainTeed ships from Corsicana TX. Atlas Roofing operates the Daingerfield TX plant. Malarkey ships from Portland OR with 5-7 day lead times. IKO ships from Canadian plants. San Antonio distributors include ABC Supply (multiple Bexar County locations), Beacon Roofing Supply, SRS Distribution, and Allied Building Products. Stone Oak and Alamo Heights dealers stock Class 4 inventory year-round given hail frequency.`,
    gutterIntegrationPara: `San Antonio gutter integration handles two distinct threats: spring thunderstorm downpours delivering 2-4 inches per hour, and rare Hill Country flash floods that overwhelm drainage systems. K-style aluminum 6-inch gutters with 3x4 downspouts are the metro standard. The Hill Country's limestone and caliche soil drains rapidly but erodes around foundations without proper downspout routing. Alamo Heights and Olmos Park tree-dense properties need gutter guards at $5-$9 per linear foot to manage live oak and pecan debris. King William's historic mansions along the San Antonio River use copper gutters on landmark-contributing structures.`,
    solarIntegrationPara: `San Antonio solar operates under CPS Energy (the nation's largest municipally owned gas and electric utility) net-metering plus the 30% federal ITC. CPS Energy's SolarHost rebate program has historically offered $0.10-$0.15 per kWh buy-back but rates fluctuate. A 7-12 kW south-facing San Antonio composition roof system returns 9-13 year payback. Texas Property Code Section 202.010 prevents HOAs from prohibiting solar but allows reasonable placement restrictions. San Antonio's 220+ annual sunshine days make it one of the better Texas solar markets outside the ERCOT wholesale-pricing zone.`,
    historicDistrictPara: `San Antonio's historic districts under HDRC jurisdiction include King William (the state's oldest residential historic district, 1867), Lavaca, Government Hill, Monte Vista, Dignowity Hill, Tobin Hill, Mahncke Park, Denver Heights, Beacon Hill, and Highland Park. The Alamo and San Antonio Missions UNESCO World Heritage Site adds a global preservation layer. Landmark review on contributing structures requires matching materials to original construction: slate and standing-seam metal on King William mansions, clay tile on Monte Vista Spanish Colonial Revival, and specific composition profiles on vernacular bungalows in Lavaca and Government Hill.`,
    commonUpsellPara: `San Antonio reroof upsells worth accepting: upgrade to Class 4 impact-rated composition (15-25% Texas premium reduction and 40-60% longer replacement interval in the hail zone), upgrade to synthetic underlayment from organic felt (survives Hill Country humidity and UV 25+ years vs 15-20 on felt), upgrade to reflective cool-roof coating on low-slope portions (CPS Energy code compliance plus 15-25F surface-temperature reduction). Upsells to decline: unnecessary Class 4 "plus" proprietary products beyond UL 2218-rated options, excessive skylight additions during reroof scope, and storm-chaser "we'll handle your insurance claim" pitches.`,
    seasonalPricingDeepPara: `San Antonio reroof pricing peaks March through June during spring-hail-claim surge and optimal install conditions. Post-hail demand spikes can push scheduling out 10-16 weeks and inflate labor rates 20-40% for 3-6 months after major events. October through February offers softer pricing (10-20% below peak) and faster scheduling. July through September surface temperatures on dark composition exceed 160F, compressing the productive daily install window to early-morning hours. Best overall pricing-and-install window: October through January, avoiding both hail surge and summer heat extremes.`,
    localRoofCountPara: `San Antonio metro (Bexar, Comal, Guadalupe, Medina, Wilson counties) has approximately 750,000 single-family homes with 3-4% annual growth. Composition dominates at roughly 87%, with Class 4 impact-rated share growing from 15% to 35% since 2016. Standing-seam metal at 6%, clay and concrete tile at 5%, and other at 2%. Average reroof cycle is 12-18 years on standard composition (hail-driven, among the shortest in the country) and 18-25+ years on Class 4 impact-rated. City of San Antonio DSD pulls approximately 20,000-35,000 roof permits annually; metro-wide runs 35,000-55,000.`,
  },
  "portland-or": {
    dominantMaterialPara: `Portland's dominant roofing is architectural composition with algae-resistant granules on 1910s-1940s bungalows and Craftsman homes across Laurelhurst, Irvington, and Sellwood, cedar shake on 1950s-1970s mid-century modern homes in the West Hills and Dunthorpe, and increasingly standing-seam metal and stone-coated steel on renovation and new construction. Moss growth on north-facing slopes is the defining Portland roof-maintenance issue: non-AR composition shows visible moss colonization within 2-4 years. Malarkey (headquartered in Portland) has the strongest local brand presence.`,
    windHailRiskPara: `Portland hail is minimal (annual expectation 0-1 damaging events) but Pacific winter windstorms drive 50-70 mph sustained gusts from October through March, with the December 2015 and January 2021 ice storms producing widespread roof damage across the metro. ASCE 7-22 rates Portland at 85-95 mph design wind speed depending on specific location. The Columbia Gorge channeling effect creates localized high-wind zones in East Portland and Troutdale. Persistent winter rain (43 inches annually) rather than acute weather events is the primary roof-degradation factor; moss, algae, and moisture drive more replacements than storm damage.`,
    permitSpecificityPara: `City of Portland Bureau of Development Services (BDS) permits residential reroofs through the online portal within 5-10 business days at $200 minimum. Beaverton, Lake Oswego, and Tigard use separate permit processes. Portland Historic Landmarks Commission oversees 20+ designated districts including Irvington, Ladd's Addition, Piedmont, Albina, Lair Hill, and King's Hill. Landmark review adds 4-8 weeks. Oregon Residential Specialty Code plus Oregon Construction Contractors Board (CCB) licensing are both required; verify CCB license status at ccb.oregon.gov before signing.`,
    warrantyCulturePara: `Malarkey Roofing Products (headquartered in Portland) dominates the local market with Vista AR (algae-resistant, 30-year), Legacy Scotchgard (Class 4, 50-year), and Highlander NEX AR (40-year rubberized asphalt). GAF Golden Pledge, OC Platinum Preferred, and CertainTeed SureStart PLUS also available through Portland distributors. Cedar shake contractors offer 15-25 year stain warranties with periodic retreatment requirements. Stone-coated steel (Decra, Gerard) carries 50-year limited lifetime warranty. Portland's persistent moisture makes AR granule and anti-moss treatment warranties functionally important.`,
    insuranceClaimCulturePara: `Oregon carriers handle windstorm and ice-storm damage under standard policies but treat moss-driven and moisture-driven decay as homeowner-responsibility maintenance. Oregon's moderate hail exposure means Class 4 impact-rated products do not drive premium incentives the way they do in Denver or Dallas. Pacific windstorm damage claims must be filed promptly; Oregon Revised Statutes Section 746.230 prohibits unfair claim settlement. The December 2015 and January 2021 ice storms produced multi-year claim backlogs that pushed metro reroof timelines to 12-16 weeks for six months afterward.`,
    localManufacturerPara: `Malarkey Roofing Products manufactures composition at three Portland-area plants (Milwaukie, Portland, Clackamas County), providing same-day or next-day delivery to every Portland jobsite. GAF ships through the Sacramento and Seattle distribution hubs. Owens Corning ships from Kansas City and Denver plants. CertainTeed ships from Shakopee MN. Atlas ships from Texas and Georgia. IKO ships from Canadian plants. Portland distributors include ABC Supply (multiple metro locations), Beacon Roofing Supply, SRS Distribution, and Pacific Supply. Malarkey's local manufacturing presence gives Portland contractors the broadest in-stock AR composition selection in the country.`,
    gutterIntegrationPara: `Portland gutter integration is critical due to 43 inches of annual rainfall concentrated from October through May. K-style aluminum 6-inch gutters with 3x4 downspouts are the metro spec; many Portland homes need 7-inch K-style on large-eave Craftsman bungalows. Gutter guards are essential ($6-$12 per linear foot) in tree-dense neighborhoods like Laurelhurst, Eastmoreland, and West Hills where Douglas fir needle debris clogs unprotected gutters within weeks. Copper gutters appear on Irvington and Portland Heights landmarked homes. Zinc-strip ridge installation ($3-$5 per linear foot) retards moss growth at the roof-gutter transition zone.`,
    solarIntegrationPara: `Portland solar adoption is moderate under the 30% federal ITC plus Portland General Electric (PGE) and Pacific Power net-metering plus Oregon Solar + Storage Rebate Program (up to $5,000). Portland's solar resource is the lowest of any major West Coast metro due to cloud cover, but the combination of federal ITC plus state rebate plus net-metering still produces 10-14 year payback on a 7-10 kW south-facing system. Pearl District and inner-eastside flat-roof solar uses ballasted racking requiring structural verification. Critical coordination: schedule reroof BEFORE solar when panels are within 3-5 years.`,
    historicDistrictPara: `Portland has 20+ locally designated historic districts under Portland Historic Landmarks Commission including Irvington, Ladd's Addition, Piedmont, Albina, Lair Hill, King's Hill/Nob Hill, Alphabet, Buckman, Sunnyside, South Portland, East Portland Grand Avenue, and Eliot. National Register listings include Laurelhurst, Eastmoreland, and Portland Heights. Landmark review on contributing structures requires matching original composition, cedar shake, or slate profiles from 1880s-1940s construction. Portland's Craftsman bungalow heritage drives specific profile requirements on contributing structures in Irvington and Laurelhurst.`,
    commonUpsellPara: `Portland reroof upsells worth accepting: upgrade to AR (algae-resistant) granules (mandatory in Portland's persistent moisture climate; non-AR shows visible moss within 2-4 years), upgrade to synthetic underlayment (Portland rain degrades organic felt in 12-18 years), zinc-strip ridge installation for continuous moss prevention ($3-$5 per linear foot, lasts 15-20 years), and upgrade to 6-foot ice-and-water-shield at eaves (Portland rarely freezes hard but east-wind ice events occur). Upsells to decline: excessive Class 4 impact-rated upgrade (Portland hail too infrequent for ROI), unnecessary powered attic ventilation, and "Pacific Northwest-specific" proprietary products without independent certification.`,
    seasonalPricingDeepPara: `Portland reroof pricing peaks June through September during the reliable dry-weather install window. October through May rainfall disrupts install scheduling; most Portland contractors stop composition work during sustained rain events and reschedule to the next dry window. This compresses peak-season demand into 4 months, making July-August bookings competitive (8-14 week lead times common). Best pricing runs late May (before peak) and October (after peak) at 10-15% below midsummer rates. Malarkey's local manufacturing means Portland contractors face fewer supply chain delays than most US metros.`,
    localRoofCountPara: `Portland metro (Multnomah, Washington, Clackamas, Clark WA counties) has approximately 680,000 single-family homes. Composition dominates at roughly 82%, cedar shake at 8% (declining as homes convert to composition or stone-coated steel), standing-seam metal at 5%, stone-coated steel at 3%, and other at 2%. Average reroof cycle is 22-30 years on AR composition (moss-managed) and 12-18 years on non-AR or unmaintained composition. Portland BDS pulls approximately 12,000-18,000 roof permits annually; metro-wide runs 30,000-50,000 in typical years.`,
  },
  "sacramento-ca": {
    dominantMaterialPara: `Sacramento's roofing market centers on concrete tile (Eagle, CalPortland) on 1990s-2020s subdivision construction in Elk Grove, Roseville, and Folsom, architectural composition on mid-century ranch homes in East Sacramento, Land Park, and Curtis Park, and flat-roof modified bitumen on older commercial-adjacent residential downtown. Sacramento's Central Valley heat drives strong demand for reflective "cool roof" coatings and light-colored tile to meet Title 24 Part 6 requirements. Standing-seam metal is growing on architect-designed homes in the Fab 40s and East Sacramento.`,
    windHailRiskPara: `Sacramento hail is minimal (annual expectation 0-1 damaging events) and windstorm exposure is low compared to coastal California. The primary Sacramento roof threats are extreme UV exposure (Sacramento sees 270+ days of sunshine) and Central Valley summer heat that pushes roof-surface temperatures above 165F on dark composition. Atmospheric-river winter storms from December through March deliver heavy rainfall and occasional high winds. ASCE 7-22 rates Sacramento at 85 mph design wind speed for most residential zones. Wildfire exposure applies in the eastern foothills near Auburn and El Dorado Hills under Chapter 7A WUI provisions.`,
    permitSpecificityPara: `City of Sacramento Community Development Department permits residential reroofs through the online portal within 5-10 business days. Sacramento County, Elk Grove, Roseville, and Folsom each have separate permit processes. California requires a C-39 Roofing Contractor license through CSLB; verify at cslb.ca.gov. Title 24 Part 6 cool-roof requirements govern low-slope replacements: minimum solar reflectance of 0.55 on initial install. Sacramento historic districts under the Preservation Commission include the Alkali Flat, Boulevard Park, Poverty Ridge, and New Era Park districts. CalRecycle mandates 65% tear-off material diversion from landfill.`,
    warrantyCulturePara: `Sacramento composition contractors offer GAF Golden Pledge, OC Platinum Preferred, and CertainTeed SureStart PLUS. Concrete tile warranties from Eagle Roofing Products run 50-75 year material with 20-25 year underlayment on synthetic systems. Title 24 cool-roof coatings carry 10-15 year reflectivity warranties with re-coating requirements. CalPortland-sourced concrete tile is locally manufactured with short lead times. CSLB requires license verification on all warranty-issuing contractors; verify at cslb.ca.gov before signing.`,
    insuranceClaimCulturePara: `Sacramento insurance carriers handle standard weather damage but the metro's low storm frequency means roof condition is a minor underwriting factor compared to Southern California fire zones. Wildfire exposure in the eastern foothills (El Dorado Hills, Auburn, Cameron Park) triggers Class A fire-rated assembly requirements and potential carrier pullbacks similar to LA and San Diego WUI zones. California FAIR Plan provides fallback coverage when private market is unavailable for foothill properties. California Insurance Code Section 790.03 prohibits unfair claim settlement practices.`,
    localManufacturerPara: `Eagle Roofing Products ships concrete tile from the Rialto CA plant with 2-3 day Sacramento delivery. CalPortland manufactures locally with same-day availability. Teichert operates aggregate and ready-mix locally. GAF composition ships through the Sacramento distribution hub with same-day pickup. Owens Corning ships from California plants. CertainTeed ships from California and Texas. Malarkey ships from Portland OR with 1-2 day Sacramento lead times (I-5 corridor proximity). Sacramento distributors include ABC Supply, Beacon Roofing Supply, SRS Distribution, and Pacific Supply. SMUD (Sacramento Municipal Utility District) coordinates net-metering for solar-integrated reroofs.`,
    gutterIntegrationPara: `Sacramento gutter integration must handle intense atmospheric-river rainfall events from December through March despite the metro's overall dry climate (only 18 inches annual rainfall). K-style aluminum 6-inch gutters with 3x4 downspouts are the metro spec. The concentration of rain into a 4-month window means gutters must handle high-volume events despite long dry periods. Valley oak and coast live oak leaf debris in East Sacramento and Curtis Park justifies gutter guards at $5-$9 per linear foot. Chinese pistache fall-color leaf drop creates dense gutter clogs in Midtown and Land Park.`,
    solarIntegrationPara: `Sacramento solar operates under SMUD (Sacramento Municipal Utility District) net-metering plus the 30% federal ITC. SMUD has historically offered some of the best municipal-utility solar programs in California, with net-metering and time-of-use rate structures that maximize solar ROI. A 7-12 kW south-facing Sacramento composition roof system returns 5-8 year payback (among the best in the country for a muni-utility territory). California NEM 3.0 applies to IOU territories but SMUD operates its own net-metering framework. Critical coordination: schedule reroof BEFORE solar when panels are within 3-5 years.`,
    historicDistrictPara: `Sacramento has locally designated historic districts under the Sacramento Preservation Commission including Alkali Flat (Sacramento's oldest neighborhood), Boulevard Park, Poverty Ridge, New Era Park, Oak Park, and Washington School. National Register listings include Old Sacramento State Historic Park, the Fab 40s, Curtis Park, and the Governor's Mansion Historic District. Landmark review on contributing structures requires matching original composition, wood shingle, or slate profiles from 1850s-1930s construction. Sacramento's Gold Rush-era and Victorian heritage drives specific material requirements on Alkali Flat and Boulevard Park contributing structures.`,
    commonUpsellPara: `Sacramento reroof upsells worth accepting: Title 24 cool-roof compliant reflective coating on low-slope replacements (code-required and delivers real energy savings), upgrade to radiant-barrier decking on pitched reroof (reduces attic surface temperature 20-30F in 100F+ Central Valley summers), upgrade to synthetic underlayment from organic felt (survives Sacramento UV 25+ years). Upsells to decline: unnecessary Class A fire-rated assembly upgrade in non-WUI zones (standard composition is adequate), excessive skylight additions during reroof scope, and "Valley-rated" proprietary products without independent certification.`,
    seasonalPricingDeepPara: `Sacramento reroof pricing peaks April through November during the extended dry-weather install window. December through March atmospheric-river rainfall disrupts scheduling, but Sacramento's rain events are shorter and less frequent than Portland or Seattle, so winter work is feasible between storms. Best pricing runs December through February (10-20% below peak) when demand drops but dry windows allow installation. July through September extreme heat (100-110F ambient) compresses productive install hours to early morning, pushing project timelines. April-May and October offer the best balance of comfortable weather and moderate demand.`,
    localRoofCountPara: `Sacramento metro (Sacramento, Placer, El Dorado, Yolo counties) has approximately 680,000 single-family homes with 2-3% annual growth. Composition covers roughly 62% of metro housing, concrete tile 28%, standing-seam metal 5%, and other 5%. Average reroof cycle is 22-30 years on composition (UV-driven in Central Valley heat) and 30-40 years on tile (underlayment-driven). Sacramento CDD pulls approximately 12,000-20,000 roof permits annually; metro-wide runs 28,000-45,000 in typical years.`,
  },
  "pittsburgh-pa": {
    dominantMaterialPara: `Pittsburgh's roofing splits distinctly across its hillside topography: architectural composition on 1920s-1950s brick and frame homes across Squirrel Hill, Shadyside, and Brookline, slate on landmarked Victorian and Queen Anne homes in Allegheny West, Manchester, and Mexican War Streets on the North Side, and modified bitumen or EPDM on flat-roof rowhouses in Lawrenceville, Bloomfield, and South Side Slopes. Pittsburgh's extreme hillside grades create unique access challenges for install crews; South Side Slopes and Mt. Washington properties may require equipment hoisting rather than ladder access.`,
    windHailRiskPara: `Pittsburgh sees 1-2 damaging hail events annually, typically in May-June supercell storms. The June 2012 derecho and August 2019 windstorm produced widespread roof damage across Allegheny County. ASCE 7-22 rates Pittsburgh at 100 mph design wind speed. Snow loading runs 25-30 psf under Pennsylvania residential code. The Three Rivers microclimate creates temperature inversions and persistent fog that accelerate moss and moisture-driven degradation on north-facing slopes, particularly in Polish Hill, Troy Hill, and Observatory Hill neighborhoods on the steep valley walls.`,
    permitSpecificityPara: `City of Pittsburgh Department of Permits, Licenses and Inspections (PLI) permits residential reroofs within 7-14 business days at $175 minimum. Allegheny County suburban municipalities (Mt. Lebanon, Upper St. Clair, Fox Chapel, Sewickley) each have separate permit processes. Pennsylvania requires Home Improvement Contractor (HIC) registration under Act 132; verify at pago.state.pa.us. Pittsburgh Historic Review Commission oversees Allegheny West, Manchester, Mexican War Streets, Deutschtown, the South Side Flats, and Friendship historic districts. Landmark review adds 6-10 weeks.`,
    warrantyCulturePara: `Pittsburgh composition contractors offer GAF Golden Pledge, OC Platinum Preferred, and CertainTeed SureStart PLUS with algae-resistant granule warranties. Slate contractors on Allegheny West and Manchester landmarked homes offer 75-100 year material warranty on Pennsylvania Bangor or Pen Argyl slate (quarried within 300 miles in the Lehigh Valley). Modified bitumen and EPDM flat-roof contractors offer Carlisle SynTec 15-20 year membrane warranties (Carlisle manufactured just 250 miles away in Carlisle PA). Pittsburgh's freeze-thaw cycling is the primary warranty claim driver.`,
    insuranceClaimCulturePara: `Pennsylvania carriers handle wind, hail, and ice-dam damage under standard homeowners policies. Pittsburgh's moderate hail frequency means Class 4 impact-rated products deliver minimal premium incentive compared to Denver or Dallas. Pennsylvania's HIC Act gives homeowners a 3-day right of rescission on any home-improvement contract. PA Attorney General Consumer Protection Division enforces unfair-practice claims under 73 P.S. Section 517. Pittsburgh's hillside topography creates unusual access-cost disputes; confirm hillside access scope and pricing before signing.`,
    localManufacturerPara: `CertainTeed is the closest major manufacturer headquarters (Malvern PA) to Pittsburgh with regional plant distribution. GAF ships through the Cleveland and Pittsburgh distribution hubs. Owens Corning manufactures at Medina OH with same-day delivery to Pittsburgh. Atlas ships from Daingerfield TX and Meridian MS. Malarkey ships from Portland OR. Carlisle SynTec manufactures modified bitumen and EPDM membrane in Carlisle PA (250 miles east) with 1-2 day delivery. Penn Big Bed Slate (Slatington PA) supplies landmarked restoration projects. Pittsburgh distributors include ABC Supply, Beacon Roofing Supply, and SRS Distribution.`,
    gutterIntegrationPara: `Pittsburgh gutter integration must manage severe hillside drainage: properties on South Side Slopes, Mt. Washington, and Polish Hill handle stormwater runoff from uphill neighbors. K-style aluminum 6-inch gutters with 3x4 downspouts are the metro spec. Ice-and-water-shield at eaves extending 3-6 feet is standard for Pittsburgh's freeze-thaw cycling. Copper gutters appear on Allegheny West and Manchester landmarked Victorian homes. Hillside properties require downspout routing engineered for slope drainage to prevent foundation erosion; the standard 4-foot downspout extension is often inadequate on Pittsburgh grades.`,
    solarIntegrationPara: `Pittsburgh solar adoption is growing under the 30% federal ITC plus Duquesne Light and FirstEnergy net-metering plus Pennsylvania Solar Renewable Energy Credits (SRECs) selling at $20-$45 per MWh in the PA compliance market. A 7-10 kW south-facing Pittsburgh composition roof system returns 8-12 year payback. Pittsburgh's solar resource is moderate due to cloud cover from the Allegheny Plateau climate, but state SRECs improve ROI. Hillside orientation affects solar array sizing; south-facing slopes in Squirrel Hill and Mt. Lebanon get optimal exposure. Critical coordination: schedule reroof BEFORE solar.`,
    historicDistrictPara: `Pittsburgh has 15+ locally designated historic districts under the Pittsburgh Historic Review Commission including Allegheny West, Manchester, Mexican War Streets, Deutschtown, South Side Flats, Friendship, Schenley Farms, Oakland Civic Center, Pittsburgh's North Shore, and portions of Lawrenceville. National Register districts add Mt. Washington, Troy Hill, and East Liberty. Landmarked review on contributing structures requires matching original slate (Pennsylvania quarry stone), specific composition profiles, or standing-seam metal matching 1850s-1920s construction. The Mexican War Streets and Allegheny West are among the finest intact Victorian districts in the Midwest.`,
    commonUpsellPara: `Pittsburgh reroof upsells worth accepting: upgrade to algae-resistant granules (Pittsburgh's Three Rivers humidity drives endemic moss on non-AR composition), upgrade ice-and-water-shield to 6-foot from eaves (Pittsburgh freeze-thaw cycling demands it), upgrade to synthetic underlayment from organic felt (moisture longevity 25+ years vs 15-20 on felt). On flat-roof rowhouses: upgrade to 80-mil EPDM or SBS modified bitumen from 60-mil. Upsells to decline: unnecessary Class 4 impact-rated upgrade (Pittsburgh hail too infrequent for ROI), hillside-access surcharges not specified in the original scope, and proprietary products without independent certification.`,
    seasonalPricingDeepPara: `Pittsburgh reroof pricing peaks April through October during the reliable install-weather window. November through March sub-freezing ambient compromises sealant activation on composition. December through February deep-freeze conditions effectively shut down pitched-roof work. Flat-roof modified bitumen and EPDM install year-round with cold-weather primers but labor premiums run 20-35% in winter. Best pricing runs late September through November (10-18% below peak). Pittsburgh's steel-heritage labor culture means union crews are common in the city proper, adding 10-15% to labor costs versus non-union suburban contractors.`,
    localRoofCountPara: `Pittsburgh metro (Allegheny, Westmoreland, Washington, Butler, Beaver, Fayette counties) has approximately 920,000 single-family and small multi-family residential structures. Composition dominates at roughly 78%, modified bitumen and EPDM on flat-roof rowhouses at 10%, slate on landmarked homes at 4%, metal at 5%, and other at 3%. Average reroof cycle is 20-28 years on composition (freeze-thaw-driven). City of Pittsburgh PLI pulls approximately 8,000-14,000 roof permits annually; metro-wide runs 35,000-55,000 in typical years.`,
  },
  "columbus-oh": {
    dominantMaterialPara: `Columbus roofing centers on architectural composition (GAF Timberline HDZ, OC Duration, CertainTeed Landmark AR) across the metro's broad suburban footprint in Dublin, Westerville, and New Albany, with mid-century ranch homes in Upper Arlington and Worthington on their second or third composition reroof. German Village's distinctive 1840s-1890s brick construction features flat-roof modified bitumen and slate-on-pitched residential. Short North townhouses and Clintonville bungalows run standard composition. Columbus's flat topography and consistent lot sizes make this one of the more production-efficient reroof markets in the Midwest.`,
    windHailRiskPara: `Columbus sees 1-3 damaging hail events annually in May-June supercell storms. The June 2012 derecho and March 2023 windstorm produced widespread damage across Franklin County. ASCE 7-22 rates Columbus at 100 mph design wind speed. Snow loading runs 20-25 psf under Ohio residential code. Columbus's relatively flat topography means wind exposure is more uniform than Pittsburgh or Cincinnati. Freeze-thaw cycling (80+ cycles annually) is the primary composition-degradation driver. Class 4 impact-rated assemblies are growing in adoption but do not drive significant Ohio premium reductions.`,
    permitSpecificityPara: `City of Columbus Department of Building and Zoning Services permits residential reroofs through the online portal within 5-10 business days at $125 minimum. Dublin, Westerville, New Albany, and Upper Arlington each have separate permit processes. Ohio does not have a statewide residential roofing contractor license; Columbus requires local contractor registration. Columbus Historic Preservation Commission oversees German Village, Victorian Village, Italian Village, Brewery District, and Olde Towne East. Landmark review adds 4-8 weeks and requires material matching to original 1840s-1920s construction.`,
    warrantyCulturePara: `Columbus composition contractors offer GAF Golden Pledge, OC Platinum Preferred, and CertainTeed SureStart PLUS. Slate contractors on German Village and Victorian Village landmarked homes offer 75-100 year material warranty on Pennsylvania or Vermont slate. Modified bitumen flat-roof contractors offer Carlisle, Elevate, or Johns Manville 15-20 year membrane warranty. Columbus's moderate hail frequency makes standard composition warranties adequate for most applications; Class 4 impact-rated products add longevity but limited premium incentive in the Ohio insurance market.`,
    insuranceClaimCulturePara: `Ohio carriers handle wind, hail, and ice-dam damage under standard homeowners policies. Columbus's moderate hail frequency does not drive Class 4 premium incentives. Ohio Revised Code Section 3905.21 prohibits unfair claim settlement practices. The Ohio Department of Insurance handles consumer complaints. Most Ohio carriers tighten roof-age underwriting on homes with 15+ year roofs. AEP Ohio and Columbia Gas offer envelope-improvement rebates but no direct roofing credits. Columbus's flat topography makes access costs consistent and predictable across the metro.`,
    localManufacturerPara: `GAF ships to Columbus through the Cleveland and Indianapolis distribution hubs with same-day or next-day pickup. Owens Corning manufactures at the Medina OH plant (150 miles northeast) with same-day delivery. CertainTeed ships from Avery OH and Shakopee MN. Atlas ships from Daingerfield TX. Malarkey ships from Portland OR. IKO ships from Canadian plants via Great Lakes. Columbus distributors include ABC Supply (multiple Franklin County locations), Beacon Roofing Supply, SRS Distribution, and Allied Building Products. Owens Corning's Ohio headquarters provides Columbus with the broadest OC product availability in the Midwest.`,
    gutterIntegrationPara: `Columbus gutter integration handles 40 inches of annual precipitation plus freeze-thaw ice-dam risk. K-style aluminum 6-inch gutters with 3x4 downspouts are the metro spec. Ice-and-water-shield at eaves extending 3 feet minimum is Ohio code. German Village's flat-roof homes require specific scupper and internal-drain systems. Clintonville and Worthington tree-dense neighborhoods need gutter guards at $5-$9 per linear foot to manage sugar maple samara (helicopter seed) and red oak leaf debris. Upper Arlington and Dublin newer construction typically includes gutter-to-underground-drain connections per subdivision standards.`,
    solarIntegrationPara: `Columbus solar adoption is growing under the 30% federal ITC plus AEP Ohio net-metering plus Ohio Solar Renewable Energy Credits (SRECs) selling at $10-$30 per MWh in the Ohio compliance market. A 7-10 kW south-facing Columbus composition roof system returns 10-14 year payback. Ohio's solar resource is moderate but improving panel efficiency narrows the gap with sunnier markets. Columbus's flat topography maximizes south-facing roof exposure. Ohio State University's Solar Roadmap initiative supports metro adoption. Critical coordination: schedule reroof BEFORE solar when panels are within 3-5 years.`,
    historicDistrictPara: `Columbus has locally designated historic districts under the Columbus Historic Preservation Commission including German Village (one of the largest privately funded historic restoration projects in the US), Victorian Village, Italian Village, Brewery District, Olde Towne East, and the Short North (transitioning from arts district to historic). National Register listings add Clintonville, Bexley, and portions of Worthington. Landmark review on contributing structures requires matching original brick, slate, composition, or wood-shingle profiles from 1840s-1920s construction. German Village's 233-acre restored district is Columbus's signature historic asset.`,
    commonUpsellPara: `Columbus reroof upsells worth accepting: upgrade to algae-resistant granules (Ohio humidity drives moss growth on non-AR composition within 3-5 years), upgrade ice-and-water-shield to 6-foot from eaves for low-slope sections (Ohio freeze-thaw cycling justifies the extension), upgrade to synthetic underlayment from organic felt. On German Village flat roofs: upgrade to 80-mil EPDM or SBS modified bitumen from 60-mil (significant longevity premium). Upsells to decline: unnecessary Class 4 impact-rated upgrade (Columbus hail too moderate for premium ROI), excessive skylight additions, and proprietary products without independent certification.`,
    seasonalPricingDeepPara: `Columbus reroof pricing peaks April through October during the reliable install-weather window. November through March sub-freezing ambient compromises sealant activation on composition. December through February deep-freeze conditions effectively stop pitched-roof work. Best pricing runs late September through November and March-April (10-18% below peak). Columbus's relatively flat topography and uniform lot sizes make the metro production-efficient for roofing crews, keeping prices competitive with other Ohio markets. Owens Corning's proximity provides Columbus contractors with shorter supply chain lead times than most US metros.`,
    localRoofCountPara: `Columbus metro (Franklin, Delaware, Licking, Fairfield, Union, Madison, Pickaway counties) has approximately 780,000 single-family homes with 2-3% annual growth (Columbus is the fastest-growing metro in Ohio). Composition dominates at roughly 86%, with flat-roof modified bitumen and EPDM at 6%, standing-seam metal at 4%, slate at 2%, and other at 2%. Average reroof cycle is 20-26 years on composition. Columbus BZS pulls approximately 12,000-20,000 roof permits annually; metro-wide runs 30,000-50,000 in typical years.`,
  },
  "kansas-city-mo": {
    dominantMaterialPara: `Kansas City's roofing market is dominated by architectural composition with growing Class 4 impact-rated adoption driven by aggressive spring hail. The metro straddles the Missouri-Kansas state line with distinct regulatory environments: Missouri side (KCMO, Independence, Lee's Summit) and Kansas side (Overland Park, Olathe, Lenexa, Shawnee) have different permitting and contractor requirements. Country Club Plaza's 1920s Spanish Revival features clay tile and copper, Brookside and Waldo run composition on 1930s-1950s brick, and newer Johnson County KS subdivisions carry standard dimensional composition.`,
    windHailRiskPara: `Kansas City sits squarely in the central US hail corridor: the metro averages 3-5 damaging hail events annually with spring supercells tracking northeast from southwestern Kansas through the metro. The May 2024 hail event produced widespread damage across Johnson County KS. ASCE 7-22 rates Kansas City at 105 mph design wind speed. Tornado corridor exposure (2003 and 2022 events affected metro suburbs) adds acute wind-uplift risk beyond hail. Class 4 impact-rated assemblies deliver 15-25% insurance premium reductions across most Missouri and Kansas carriers.`,
    permitSpecificityPara: `Kansas City MO Neighborhoods and Community Development permits residential reroofs within 5-10 business days. Johnson County KS municipalities (Overland Park, Olathe, Shawnee) each require separate permits with stricter inspection requirements than the MO side. Missouri has no statewide roofer license; Kansas requires contractor registration through the Kansas Attorney General. KCMO Historic Preservation Commission oversees the Country Club Plaza, Pendleton Heights, Scarritt Renaissance, Janssen Place, and Northeast neighborhoods. Johnson County KS has stricter code enforcement including mandatory nailing-pattern verification inspections.`,
    warrantyCulturePara: `Kansas City Class 4 installations anchor on Malarkey Legacy (50-year SBS-modified), GAF Timberline AS, IKO Dynasty, and Atlas Pinnacle Pristine. Standard composition uses GAF Golden Pledge, OC Platinum Preferred, and CertainTeed SureStart PLUS. Kansas hail frequency makes impact-resistance warranty functionally critical: standard composition typically needs replacement every 8-14 years in the KC corridor, while Class 4 extends that to 18-25 years. Clay tile on Country Club Plaza runs Eagle Roofing Products or US Tile 50-year material warranty.`,
    insuranceClaimCulturePara: `Missouri and Kansas carriers both aggressively incentivize Class 4: most Kansas City policies yield 15-25% premium reductions. Post-hail storm-chase crews are the highest-risk contractor category in the KC market; verify local business registration and Kansas/Missouri licensing before signing. Missouri hail claims must be filed promptly; Kansas has a 2-year statute of limitations. The dual-state metro means carriers may apply different policies on the MO vs KS side; confirm which state your property is in and which carrier rules apply.`,
    localManufacturerPara: `GAF ships to Kansas City through the local KC distribution hub with same-day pickup. Owens Corning manufactures at the Kansas City plant with same-day delivery across the entire metro. CertainTeed ships from Shakopee MN. Atlas ships from Daingerfield TX. Malarkey ships from Portland OR with 4-6 day lead times. IKO ships from Canadian plants. Ash Grove Cement (KC-headquartered) supplies concrete for masonry-related roof work. Kansas City distributors include ABC Supply (multiple metro locations on both sides of the state line), Beacon Roofing Supply, SRS Distribution, and Allied Building Products.`,
    gutterIntegrationPara: `Kansas City gutter integration handles both spring thunderstorm downpours and winter ice-dam risk from 80+ freeze-thaw cycles annually. K-style aluminum 6-inch gutters with 3x4 downspouts are the metro spec. Ice-and-water-shield at eaves extending 3-6 feet is the Kansas City standard for the region's freeze-thaw severity. Bur oak and hackberry leaf debris in Brookside, Waldo, and Prairie Village neighborhoods justifies gutter guards at $5-$9 per linear foot. Country Club Plaza's clay-tile roofs require specific hanger bracket selection for K-style or half-round copper gutters.`,
    solarIntegrationPara: `Kansas City solar operates under Evergy (formerly KCP&L) net-metering on both the MO and KS sides plus the 30% federal ITC. Missouri's renewable energy standard requires 15% renewable by 2021. Kansas has no state renewable mandate. A 7-10 kW south-facing KC composition roof system returns 10-14 year payback. Kansas City's 220+ annual sunshine days provide moderate solar resource. The dual-state metro means solar incentives may differ between MO-side (Evergy Missouri) and KS-side (Evergy Kansas) properties. Critical coordination: schedule reroof BEFORE solar when panels are within 3-5 years.`,
    historicDistrictPara: `Kansas City has locally designated historic districts under the KCMO Historic Preservation Commission including the Country Club Plaza (the first planned shopping center in the US, 1922), Pendleton Heights, Scarritt Renaissance, Janssen Place, Northeast, Santa Fe, and Westport. National Register listings add Hyde Park, Valentine, and Corinthian Hall neighborhoods. Kansas-side Overland Park and Prairie Village have limited historic designation. Landmark review on MO-side contributing structures requires matching original clay tile, composition, or slate profiles from 1880s-1930s construction.`,
    commonUpsellPara: `Kansas City reroof upsells worth accepting: Class 4 impact-rated composition (15-25% MO/KS premium reduction plus dramatically extended replacement interval in the hail corridor), upgrade to synthetic underlayment from organic felt (freeze-thaw cycling degrades felt in 12-18 years), upgrade ice-and-water-shield to 6-foot from eaves (Kansas City's 80+ freeze-thaw cycles justify extended coverage). On Country Club Plaza: clay-tile underlayment replacement with Polyglass synthetic 30-year system. Upsells to decline: storm-chaser deductible-eating offers (Texas Insurance Code violation applies to Kansas too), proprietary products without independent UL 2218 certification.`,
    seasonalPricingDeepPara: `Kansas City reroof pricing peaks April through June during spring-hail-claim surge. Post-major-hail-event demand spikes push scheduling out 10-16 weeks and inflate labor rates 20-40% for 3-6 months. October through February offers softer pricing (10-20% below peak) and faster scheduling. Sub-freezing ambient from December through February stops composition installation. Johnson County KS inspectors enforce strict nailing-pattern verification that adds 1-2 days to project completion. Best overall window: September through November, after hail season but before deep freeze.`,
    localRoofCountPara: `Kansas City metro (Jackson, Clay, Platte, Cass MO plus Johnson, Wyandotte, Douglas KS) has approximately 820,000 single-family homes. Composition dominates at roughly 85%, with Class 4 impact-rated share growing from 12% to 30% since 2018. Clay tile at 4%, standing-seam metal at 6%, and other at 5%. Average reroof cycle is 12-18 years on standard composition (hail-driven, among the shortest in the US) and 18-25 years on Class 4. KCMO plus KC-area jurisdictions pull approximately 25,000-40,000 roof permits annually metro-wide.`,
  },
  "indianapolis-in": {
    dominantMaterialPara: `Indianapolis roofing centers on architectural composition across the metro's expansive suburban footprint in Carmel, Fishers, Noblesville, and Zionsville. Meridian-Kessler and Broad Ripple feature 1920s-1940s Tudor Revival and Colonial homes on their second or third composition reroof. Irvington and Woodruff Place historic districts feature slate and standing-seam metal on Victorian and Queen Anne landmarked homes. Fountain Square and Bates-Hendricks townhouses run flat-roof modified bitumen. Indianapolis's flat topography and uniform grid make it a production-efficient reroof market.`,
    windHailRiskPara: `Indianapolis sees 2-3 damaging hail events annually in spring supercell storms. The April 2023 and May 2024 hail events produced widespread damage across Marion and Hamilton counties. ASCE 7-22 rates Indianapolis at 100 mph design wind speed. Tornado corridor exposure (the November 2013 EF2 in Washington Township and recurring supercell activity) adds acute wind-uplift risk. Snow loading runs 20-25 psf under Indiana residential code. Freeze-thaw cycling (85+ cycles annually) is the primary composition-degradation driver. Class 4 impact-rated assemblies are growing but Indiana premium incentives are moderate.`,
    permitSpecificityPara: `City of Indianapolis Department of Business and Neighborhood Services (BNS) permits residential reroofs through the Accela portal within 5-10 business days at $100 minimum. Carmel, Fishers, Noblesville, and Zionsville each have separate permit processes. Indiana does not have a statewide residential roofing contractor license but requires contractor registration in Marion County. Indianapolis Historic Preservation Commission (IHPC) oversees Irvington, Lockerbie Square, Woodruff Place, Herron-Morton Place, Fletcher Place, and Old Northside historic districts. Landmark review adds 4-8 weeks.`,
    warrantyCulturePara: `Indianapolis composition contractors offer GAF Golden Pledge, OC Platinum Preferred, and CertainTeed SureStart PLUS. Class 4 impact-rated products (Malarkey Legacy, GAF Timberline AS) are growing in adoption post-2023 hail events. Slate contractors on Irvington and Woodruff Place landmarked homes offer 75-100 year material warranty on Indiana limestone-compatible Pennsylvania or Vermont slate. Irving Materials (IMI, headquartered in Greenfield IN) supplies concrete and aggregate for masonry-adjacent roof work and is a significant local employer in the construction trades.`,
    insuranceClaimCulturePara: `Indiana carriers handle wind, hail, and ice-dam damage under standard homeowners policies. Indiana hail frequency is moderate, yielding 5-15% premium reductions for Class 4 impact-rated assemblies on most carriers. Indiana Insurance Code Title 27 Article 4 prohibits unfair claim settlement practices. Indiana Department of Insurance handles consumer complaints. Post-hail storm-chase crews from surrounding states appear in Indianapolis after spring events; verify Indiana business registration and insurance before signing. Document hail damage within 30 days of any event.`,
    localManufacturerPara: `GAF ships to Indianapolis through the Cleveland and Kansas City distribution hubs with 1-2 day lead times. Owens Corning manufactures at Medina OH and Kansas City plants with 1-2 day delivery. CertainTeed ships from Shakopee MN and Avery OH. Atlas ships from Daingerfield TX. Malarkey ships from Portland OR. IKO ships from Canadian plants. Irving Materials (IMI) headquartered in Greenfield IN is a major construction-supply presence but does not manufacture roofing products. Indianapolis distributors include ABC Supply (multiple Marion County locations), Beacon Roofing Supply, SRS Distribution, and Allied Building Products.`,
    gutterIntegrationPara: `Indianapolis gutter integration handles 42 inches of annual precipitation plus 85+ freeze-thaw cycles. K-style aluminum 6-inch gutters with 3x4 downspouts are the metro spec. Ice-and-water-shield at eaves extending 3 feet minimum is code for Indiana's climate zone. Meridian-Kessler and Broad Ripple tree-dense neighborhoods need gutter guards at $5-$9 per linear foot to manage tulip poplar seed pods and sweetgum spiked-ball debris. Carmel and Fishers newer subdivisions typically include gutter-to-underground-drain connections per HOA and subdivision standards.`,
    solarIntegrationPara: `Indianapolis solar adoption is moderate under the 30% federal ITC plus AES Indiana net-metering plus Indiana Excess Distributed Generation credit. Indiana's net-metering framework provides retail-rate credits but legislation has reduced compensation rates over time. A 7-10 kW south-facing Indianapolis composition roof system returns 10-14 year payback. Indianapolis's flat topography maximizes south-facing roof exposure. Indiana's solar resource is moderate but competitive with other Midwest markets. Critical coordination: schedule reroof BEFORE solar when panels are within 3-5 years.`,
    historicDistrictPara: `Indianapolis has locally designated historic districts under IHPC jurisdiction including Irvington (one of the first planned suburban communities in Indiana, 1870), Lockerbie Square, Woodruff Place, Herron-Morton Place, Fletcher Place, Old Northside, Chatham-Arch, St. Joseph, Ransom Place, and Fall Creek Place. National Register listings add Meridian-Kessler, Broad Ripple, and portions of Mapleton-Fall Creek. Landmark review on contributing structures requires matching original slate, composition, or wood-shingle profiles from 1850s-1920s construction. Woodruff Place's original 1876 plat design makes it one of Indianapolis's most architecturally intact Victorian neighborhoods.`,
    commonUpsellPara: `Indianapolis reroof upsells worth accepting: upgrade to algae-resistant granules (Indiana humidity drives moss growth on non-AR composition within 4-6 years), upgrade ice-and-water-shield to 6-foot from eaves (Indianapolis 85+ freeze-thaw cycles justify extended coverage), upgrade to synthetic underlayment from organic felt. On historic district homes: proper matching of original material profile is mandatory scope, not an upsell. Upsells to decline: unnecessary Class 4 impact-rated upgrade where Indiana premium incentive is minimal, excessive skylight additions, and proprietary products without independent UL or ASTM certification.`,
    seasonalPricingDeepPara: `Indianapolis reroof pricing peaks April through October during the reliable install-weather window. November through March sub-freezing ambient stops most composition installation. December through February deep-freeze conditions effectively shut down all pitched-roof work. Best pricing runs September-November (10-18% below peak) and early April before spring hail season. Post-hail demand spikes can push scheduling out 8-14 weeks and inflate labor rates 15-30% for 3-6 months. Indianapolis's flat topography and grid layout make it one of the most production-efficient reroof markets in the Midwest.`,
    localRoofCountPara: `Indianapolis metro (Marion, Hamilton, Hendricks, Johnson, Boone, Hancock, Madison, Morgan, Shelby counties) has approximately 760,000 single-family homes with 2-3% annual growth. Composition dominates at roughly 88%, with flat-roof modified bitumen and EPDM at 5%, standing-seam metal at 4%, slate at 1%, and other at 2%. Average reroof cycle is 18-24 years on composition (freeze-thaw and moderate hail-driven). Indianapolis BNS pulls approximately 10,000-18,000 roof permits annually; metro-wide runs 28,000-45,000 in typical years.`,
  },
  "nashville-tn": {
    dominantMaterialPara: `Nashville's roofing market features architectural composition across the metro's rapidly growing suburban footprint in Franklin, Brentwood, Mt. Juliet, and Hendersonville. Historic neighborhoods in East Nashville, Germantown, and 12South run composition and standing-seam metal on 1890s-1930s Victorian, shotgun, and Craftsman homes. The Sylvan Park and West End corridors feature 1940s-1950s brick ranch homes on their second or third composition reroof. Nashville's explosive growth (the metro added 100,000+ people 2020-2025) has created labor scarcity that pushes reroof timelines 2-4 weeks longer than comparably sized Midwest metros.`,
    windHailRiskPara: `Nashville sees 2-3 damaging hail events annually in spring supercell storms, and the March 2020 EF3 tornado devastated East Nashville, Germantown, Donelson, and Mt. Juliet with direct-hit wind damage. ASCE 7-22 rates Davidson County at 100 mph design wind speed. The March 2020 event produced 40,000+ roof claims in Davidson County alone and pushed metro reroof timelines to 16-20 weeks for 12 months afterward. Tennessee's position in the Nashville Basin between the Highland Rim escarpments channels severe weather through the metro corridor. Class 4 impact-rated assemblies deliver modest 5-15% premium reductions on Tennessee carriers.`,
    permitSpecificityPara: `Metropolitan Nashville Department of Codes Administration permits residential reroofs through the online portal within 5-10 business days at $150 minimum. Williamson County (Franklin, Brentwood), Wilson County (Mt. Juliet), and Sumner County (Hendersonville) each require separate permits. Tennessee does not have a statewide residential roofing contractor license but requires Tennessee Home Improvement License for projects over $3,000. Metro Nashville Historic Zoning Commission oversees East Nashville, Germantown, Lockeland Springs, 12South, and Hillsboro Village. Landmark review adds 4-8 weeks.`,
    warrantyCulturePara: `Nashville composition contractors offer GAF Golden Pledge, OC Platinum Preferred, and CertainTeed SureStart PLUS. The March 2020 tornado aftermath drove significant adoption of higher-wind-rated products: GAF HDZ at 130 mph wind warranty, OC Duration STORM at 130 mph, and Malarkey Legacy at Class 4 impact rating are increasingly common Nashville specifications. Standing-seam metal on East Nashville and Germantown renovations carries 40-50 year paint plus 50-year substrate warranty. Nashville's rapid growth has attracted national-brand contractor networks (Dreamstyle, Leaf Home) alongside established local firms.`,
    insuranceClaimCulturePara: `Tennessee carriers handle wind, hail, and tornado damage under standard homeowners policies. The March 2020 tornado event produced the largest single-event residential claim volume in Nashville history. Tennessee Insurance Division (Department of Commerce and Insurance) handles consumer complaints. Post-2020, most Nashville carriers tightened roof-age underwriting and many require roof inspection on 15+ year homes. Class 4 impact-rated assemblies yield 5-15% premium reductions. Document storm damage within 30 days; Tennessee has a 1-year statute of limitations for property damage claims.`,
    localManufacturerPara: `GAF ships to Nashville through the Atlanta and Shreveport distribution hubs with 1-2 day lead times. Owens Corning ships from the Irving TX and Kansas City plants. CertainTeed ships from Corsicana TX and Shreveport LA. Atlas Roofing ships from Cordele GA with 1-day Nashville delivery. Malarkey ships from Portland OR. Firestone Building Products (now Elevate) is headquartered in Nashville, providing direct manufacturer relationships for flat-roof EPDM and TPO projects. Nashville distributors include ABC Supply (multiple Davidson County locations), Beacon Roofing Supply, SRS Distribution, and Allied Building Products.`,
    gutterIntegrationPara: `Nashville gutter integration handles 48 inches of annual precipitation spread across the year plus 40+ freeze-thaw cycles. K-style aluminum 6-inch gutters with 3x4 downspouts are the metro spec. Nashville's clay soils and sloped topography in East Nashville, 12South, and Bellevue require downspout routing away from foundations to prevent settling. Ice-and-water-shield at eaves extending 3 feet minimum is standard for Nashville's moderate freeze-thaw climate. Eastern red cedar and hackberry leaf debris in Green Hills and Belle Meade justifies gutter guards at $5-$9 per linear foot.`,
    solarIntegrationPara: `Nashville solar adoption is moderate under the 30% federal ITC plus Nashville Electric Service (NES) net-metering. NES provides 1-for-1 retail-rate credits for exported solar energy. Tennessee does not have a state renewable portfolio standard, so the federal ITC is the primary incentive driver. A 7-10 kW south-facing Nashville composition roof system returns 10-14 year payback. Nashville's solar resource is moderate at approximately 4.2 peak sun hours daily. Tennessee Valley Authority (TVA) wholesale rates to NES keep electricity affordable, which lengthens solar payback versus higher-rate markets. Critical coordination: schedule reroof BEFORE solar.`,
    historicDistrictPara: `Nashville has locally designated historic districts under the Metro Nashville Historic Zoning Commission including East Nashville (Lockeland Springs, Edgefield, McFerrin Park), Germantown, 12South, Hillsboro-West End, Belmont-Hillsboro, and portions of Sylvan Park and Salemtown. National Register districts add Music Row, Marathon Village, and the downtown Second Avenue commercial district (rebuilt after the December 2020 bombing). Landmark review on contributing structures requires matching original composition, standing-seam metal, or slate profiles from 1880s-1940s construction. East Nashville's post-tornado 2020 rebuild brought significant new construction into the historic overlay zone.`,
    commonUpsellPara: `Nashville reroof upsells worth accepting: upgrade to 130-mph wind-rated composition (the March 2020 tornado demonstrated the value of high-wind products in Nashville's severe-weather corridor), upgrade to synthetic underlayment from organic felt (Nashville humidity degrades felt in 15-20 years), upgrade to ice-and-water-shield at eaves (Nashville's moderate freeze-thaw cycling justifies it). On historic-district homes: proper material matching is mandatory scope. Upsells to decline: unnecessary Class 4 impact-rated upgrade where TN premium incentive is minimal, excessive powered attic ventilation, and proprietary products without independent certification.`,
    seasonalPricingDeepPara: `Nashville reroof pricing peaks March through June during spring-storm-claim surge and optimal install conditions before summer heat. Post-tornado demand (March 2020 aftermath) pushed Nashville reroof timelines to 16-20 weeks and inflated pricing for 12+ months. October through February offers softer pricing (10-20% below peak) and faster scheduling. July-August heat above 95F compresses the productive daily install window. Best overall window: September through November, after storm season but before winter slowdown. Nashville's rapid population growth has created persistent labor scarcity that keeps baseline pricing 5-10% above comparable Midwest metros.`,
    localRoofCountPara: `Nashville metro (Davidson, Williamson, Rutherford, Wilson, Sumner, Robertson counties) has approximately 680,000 single-family homes with 3-4% annual growth (Nashville is one of the fastest-growing major metros in the US). Composition dominates at roughly 84%, standing-seam metal at 7% (higher than most Midwest markets, reflecting Nashville's design culture), flat-roof modified bitumen at 4%, slate at 2%, and other at 3%. Average reroof cycle is 18-24 years on composition. Metro Nashville Codes Administration pulls approximately 12,000-20,000 roof permits annually; metro-wide runs 30,000-50,000 in typical years.`,
  },
};

// EXTRA2 data
