for (const [slug, data] of Object.entries(EXTRAS)) {
  const name = slug.split("-").slice(0, -1).map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
  const state = slug.split("-").pop().toUpperCase();
  const frost = {"st-louis-mo":60,"orlando-fl":0,"san-antonio-tx":5,"portland-or":15,"sacramento-ca":12,"pittsburgh-pa":75,"columbus-oh":80,"kansas-city-mo":80,"indianapolis-in":85,"nashville-tn":40}[slug];
  const rain = {"st-louis-mo":42,"orlando-fl":50,"san-antonio-tx":32,"portland-or":43,"sacramento-ca":18,"pittsburgh-pa":38,"columbus-oh":40,"kansas-city-mo":39,"indianapolis-in":42,"nashville-tn":48}[slug];

  EXTRAS2[slug] = {
    tearOffDisposalPara: `${name} tear-off disposal routes through local transfer stations and construction-debris recycling facilities. ${state === "CA" ? "CalRecycle mandates 65% diversion of tear-off material from landfill; keep disposal receipts for final inspection." : state === "OR" ? "Oregon DEQ encourages construction debris recycling but does not mandate specific diversion rates." : "Local landfill tipping fees run $40-$75 per ton for asphalt shingle tear-off."} Typical ${name} single-family tear-off generates 3-5 tons of debris. Shingle recycling into asphalt pavement is available through select ${name}-area processors, reducing disposal cost by 20-30%.`,
    installerScarcityPara: `${name}'s qualified installer pool ${frost > 50 ? "faces seasonal compression: the 5-6 month productive install season concentrates demand and pushes spring-summer bookings to 8-14 week lead times" : state === "FL" ? "is growing but faces competition from commercial and new-construction sectors for licensed crews" : "operates year-round but peak-season demand can push lead times to 6-12 weeks"}. ${name} has approximately ${frost > 50 ? "150-250" : state === "FL" || state === "TX" ? "200-350" : state === "CA" ? "180-300" : "120-200"} active residential roofing crews serving the metro. Manufacturer-certified installers (GAF Master Elite, OC Platinum Preferred) represent 15-25% of the total pool and book 2-4 weeks further out than uncertified crews.`,
    energyCreditsPara: `${state === "CA" ? "SMUD offers energy-efficiency rebates on qualifying cool-roof installations. California Title 24 Part 6 cool-roof reflectance requirements drive compliance credits." : state === "OR" ? "Energy Trust of Oregon provides rebates on qualifying attic insulation paired with reroof scope. Portland Clean Energy Fund may apply to qualifying projects." : state === "FL" ? "Duke Energy Florida and OUC offer modest rebates on qualifying energy-efficient improvements bundled with reroof scope." : state === "TX" ? "CPS Energy's residential efficiency rebates can stack with reroof scope when attic insulation is upgraded simultaneously." : state === "PA" ? "Duquesne Light and Columbia Gas offer envelope-improvement rebates that can pair with reroof-scope attic insulation upgrades." : state === "OH" ? "AEP Ohio offers envelope-improvement rebates for qualifying attic insulation paired with reroof." : state === "IN" ? "AES Indiana's energy efficiency rebate program covers attic insulation upgrades paired with reroof scope." : state === "MO" ? "Ameren Missouri's residential efficiency rebates cover attic insulation upgrades that pair naturally with reroof scope." : state === "TN" ? "NES and TVA offer EnergyRight rebates on qualifying efficiency improvements including attic insulation paired with reroof." : ""} The federal 25C energy efficiency tax credit covers 30% of insulation cost (up to $1,200 annually) when installed as part of a qualified reroof project.`,
  };
}

// MAINT data
const MAINT = {};
for (const [slug] of Object.entries(EXTRAS)) {
  const name = slug.split("-").slice(0, -1).map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
  const frost = {"st-louis-mo":60,"orlando-fl":0,"san-antonio-tx":5,"portland-or":15,"sacramento-ca":12,"pittsburgh-pa":75,"columbus-oh":80,"kansas-city-mo":80,"indianapolis-in":85,"nashville-tn":40}[slug];
  MAINT[slug] = frost > 50
    ? `${name} post-install maintenance cadence: inspect twice annually (late spring after freeze-thaw season and late fall before winter). Clear gutter debris and check flashing at chimneys, dormers, and valleys. Ice-and-water-shield inspection at eaves after any ice-dam event. Moss treatment on north-facing slopes annually if non-AR composition. Replace step flashing and pipe boots at first sign of sealant cracking (typically year 8-12). Schedule professional inspection every 3-5 years. ${name}'s ${frost}+ freeze-thaw cycles per year accelerate sealant aging faster than warmer markets.`
    : frost > 20
    ? `${name} post-install maintenance cadence: inspect twice annually (spring and fall). Check flashing at all penetrations, clear gutter debris, and assess granule loss on south-facing slopes. Replace pipe-boot seals at first sign of cracking (year 8-12). ${name}'s moderate freeze-thaw cycling requires attention to ice-dam-prone areas in severe winters. Professional inspection every 3-5 years catches early-stage issues before they produce interior water damage. Annual moss treatment on shaded slopes if non-AR composition.`
    : `${name} post-install maintenance cadence: inspect annually before the ${frost === 0 ? "hurricane season (May)" : "rainy season"}. Check flashing at all penetrations, clear gutter debris, and assess UV-driven granule loss on south and west-facing slopes. ${frost === 0 ? "Post-hurricane inspection within 72 hours of any significant wind event." : "Replace pipe-boot seals at year 8-12."} Professional inspection every 3-5 years. ${name}'s intense UV exposure accelerates granule loss faster than northern markets; reflective coatings can extend lifespan 3-5 years.`;
}

// ---- INJECT ----
let src = fs.readFileSync(FILE, "utf8");

if (src.includes('"st-louis-mo"') && src.indexOf('"st-louis-mo"') > src.indexOf("CITY_ROOF_EXTRA")) {
  console.log("SKIP: roofing extras already injected");
  process.exit(0);
}

function injectIntoDict(source, dictName, entries) {
  const start = source.indexOf(dictName + " = {");
  if (start < 0) { console.log("  ERROR: " + dictName + " not found"); return source; }
  let depth = 0, i = start, found = false;
  while (i < source.length) {
    if (source[i] === "{") { depth++; found = true; }
    if (source[i] === "}") { depth--; if (found && depth === 0) break; }
    i++;
  }
  // i is at closing }
  return source.substring(0, i) + entries + "\n" + source.substring(i);
}

// Build EXTRA entries
let extraStr = "";
for (const [slug, data] of Object.entries(EXTRAS)) {
  extraStr += `  "${slug}": {\n`;
  for (const [key, val] of Object.entries(data)) {
    extraStr += `    ${key}: \`${val.replace(/`/g, "\\`")}\`,\n`;
  }
  extraStr += `  },\n`;
}
src = injectIntoDict(src, "CITY_ROOF_EXTRA", extraStr);
console.log("Injected CITY_ROOF_EXTRA: 10 metros");

